export interface PetSprites {
  idle: SpriteData[]     // Sitting, tail wagging
  walk: SpriteData[]     // Running/jumping (fallback for non-directional)
  sleep: SpriteData[]    // Lying down
  scared: SpriteData[]   // Bristled/attack mode
  walkDown?: SpriteData[]   // Directional walk (optional)
  walkUp?: SpriteData[]
  walkLeft?: SpriteData[]
  walkRight?: SpriteData[]
}

